                client_minor,
                server_minor,
            } => {
                warn!(
                    client_version = %client_ver,
                    server_version = %SchemaVersion::current(),
                    client_minor = %client_minor,
                    server_minor = %server_minor,
                    "Client schema version is newer than server"
                );
            }
            VersionCompatibility::ServerNewer { .. } => {
                debug!(
                    client_version = %client_ver,
                    server_version = %SchemaVersion::current(),
