            let composite_key = format!("set:{}::{}", key, member);
            let mut data = self.data.write().await;
            data.insert(composite_key, vec![1]);
            Ok(())
        }

async fn set_remove(&self, key: &str, member: &str) -> Result<(), StorageError> {
            let composite_key = format!("set:{}::{}", key, member);
            let mut data = self.data.write().await;
            data.remove(&composite_key);
