        }

async fn set_members(&self, key: &str) -> Result<Vec<String>, StorageError> {
            let prefix = format!("set:{}::", key);
            let data = self.data.read().await;
            Ok(data
                .keys()
                .filter(|k| k.starts_with(&prefix))
                .map(|k| k[prefix.len()..].to_string())
                .collect())
