    ///     if let Some(data) = value {
    ///         println!("{}: {} bytes", key, data.len());
    ///     }
    /// }
    /// ```
    async fn batch_get(&self, keys: &[String]) -> Result<Vec<Option<Vec<u8>>>, StorageError>;
